function parseTweetId(input) {
	const trimmed = input.trim();
	if (/^\d+$/.test(trimmed)) return trimmed;
	return trimmed.match(/(?:twitter\.com|x\.com)\/\w+\/status\/(\d+)/)?.[1] ?? null;
}
